// Calculate date ranges for various metric windows
const now = new Date();
const today = now.toISOString().split('T')[0];

const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000);
const yesterdayStr = yesterday.toISOString().split('T')[0];
const yesterdayStart = yesterdayStr + 'T00:00:00Z';
const yesterdayEnd = yesterdayStr + 'T23:59:59.999Z';

const sevenDaysAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
const sevenDaysAgoStr = sevenDaysAgo.toISOString().split('T')[0] + 'T00:00:00Z';

const thirtyDaysAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
const thirtyDaysAgoStr = thirtyDaysAgo.toISOString().split('T')[0] + 'T00:00:00Z';

return [{ json: {
  today,
  yesterdayStr,
  yesterdayStart,
  yesterdayEnd,
  sevenDaysAgoStr,
  thirtyDaysAgoStr,
  nowIso: now.toISOString()
} }];

// Calculate all KPI metrics from the fetched data
const dates = $('Calculate Date Ranges').first().json;

// === LEADS TOTAL ===
const leadsCountHeader = $('Count Total Leads').first().json.headers?.['content-range'] || '';
const leadsTotal = parseInt(leadsCountHeader.split('/')[1] || '0', 10) || 0;

// === LEADS 7-DAY (for conversion) ===
const leads7d = $('Fetch Leads 7-Day').first().json.body || [];
const leads7dTotal = Array.isArray(leads7d) ? leads7d.length : 0;
const leads7dConverted = Array.isArray(leads7d) ? leads7d.filter(l => l.status === 'booked' || l.status === 'completed').length : 0;
const conversionRate = leads7dTotal > 0 ? Math.round((leads7dConverted / leads7dTotal) * 10000) / 100 : 0;

// === LEADS BY SOURCE (7-day) ===
const sourceMap = {};
if (Array.isArray(leads7d)) {
  for (const lead of leads7d) {
    const src = (lead.source || 'unknown').toLowerCase();
    sourceMap[src] = (sourceMap[src] || 0) + 1;
  }
}

// === REVENUE ===
const revenue30d = $('Fetch Revenue 30-Day').first().json.body || [];
const revenueArr = Array.isArray(revenue30d) ? revenue30d : [];
const revenueTotal = revenueArr.reduce((sum, r) => sum + (parseFloat(r.revenue) || 0), 0);
const avgJobValue = revenueArr.length > 0 ? Math.round((revenueTotal / revenueArr.length) * 100) / 100 : 0;

// Revenue today (from yesterday's TG-107 sync)
const todayRevenue = revenueArr
  .filter(r => r.attributed_at && r.attributed_at.startsWith(dates.yesterdayStr))
  .reduce((sum, r) => sum + (parseFloat(r.revenue) || 0), 0);

// === SMS RESPONSE RATE (yesterday) ===
const smsData = $('Fetch SMS Yesterday').first().json.body || [];
const smsArr = Array.isArray(smsData) ? smsData : [];
const smsTotal = smsArr.length;
const smsDelivered = smsArr.filter(s => s.delivered_at !== null).length;
const smsResponseRate = smsTotal > 0 ? Math.round((smsDelivered / smsTotal) * 10000) / 100 : 0;

// === EMAIL OPEN RATE (yesterday) ===
const emailData = $('Fetch Email Yesterday').first().json.body || [];
const emailArr = Array.isArray(emailData) ? emailData : [];
const emailTotal = emailArr.length;
const emailOpened = emailArr.filter(e => e.opened_at !== null).length;
const emailOpenRate = emailTotal > 0 ? Math.round((emailOpened / emailTotal) * 10000) / 100 : 0;

// === QUOTE CONVERSION RATE (7-day, quoted -> booked) ===
const quoted7d = Array.isArray(leads7d) ? leads7d.filter(l => l.status === 'quoted' || l.status === 'booked' || l.status === 'completed').length : 0;
const bookedFromQuote7d = Array.isArray(leads7d) ? leads7d.filter(l => l.status === 'booked' || l.status === 'completed').length : 0;
const quoteConversionRate = quoted7d > 0 ? Math.round((bookedFromQuote7d / quoted7d) * 10000) / 100 : 0;

// Build all metrics for upsert
const metricDate = dates.today;
const metrics = [
  { metric_date: metricDate, metric_name: 'leads_total', metric_value: leadsTotal },
  { metric_date: metricDate, metric_name: 'revenue_total', metric_value: Math.round(todayRevenue * 100) / 100 },
  { metric_date: metricDate, metric_name: 'avg_job_value', metric_value: avgJobValue },
  { metric_date: metricDate, metric_name: 'conversion_rate', metric_value: conversionRate },
  { metric_date: metricDate, metric_name: 'sms_response_rate', metric_value: smsResponseRate },
  { metric_date: metricDate, metric_name: 'email_open_rate', metric_value: emailOpenRate },
  { metric_date: metricDate, metric_name: 'quote_conversion_rate', metric_value: quoteConversionRate },
  { metric_date: metricDate, metric_name: 'leads_by_source_google_organic', metric_value: sourceMap['google_organic'] || sourceMap['google organic'] || sourceMap['organic'] || 0 },
  { metric_date: metricDate, metric_name: 'leads_by_source_google_ads', metric_value: sourceMap['google_ads'] || sourceMap['google ads'] || sourceMap['lsa'] || 0 },
  { metric_date: metricDate, metric_name: 'leads_by_source_referral', metric_value: sourceMap['referral'] || 0 },
  { metric_date: metricDate, metric_name: 'leads_by_source_direct', metric_value: sourceMap['direct'] || sourceMap['website'] || 0 },
  { metric_date: metricDate, metric_name: 'leads_by_source_nextdoor', metric_value: sourceMap['nextdoor'] || 0 },
  { metric_date: metricDate, metric_name: 'leads_by_source_facebook', metric_value: sourceMap['facebook'] || 0 }
];

return [{ json: { metrics, metricDate, summary: {
  leadsTotal,
  todayRevenue: Math.round(todayRevenue * 100) / 100,
  avgJobValue,
  conversionRate,
  smsResponseRate,
  emailOpenRate,
  quoteConversionRate,
  metricsCount: metrics.length
} } }];

// Log completion summary
const data = $('Calculate All KPIs').first().json;
return [{ json: {
  status: 'complete',
  metricDate: data.metricDate,
  metricsUpserted: data.metrics.length,
  summary: data.summary,
  completedAt: new Date().toISOString()
} }];
